<template>
  <div class="add-body">
    <!--main-->
    <div class="add-content" >
      <!--con-->
      <div class="add-content_row" style="height: 4vh;padding-top:2vh">
        <div class="add-content_col">
          <span><i>*</i>用户名称</span>
          <span>
            <el-input
            v-model="userForm['username']"></el-input>
          </span>
        </div>
        <div class="add-content_col">
          <span><i>*</i>登录密码</span>
          <span>
            <el-input
            v-model="password" type="password" :disabled="UserMsg.type == 'edit'"></el-input>
          </span>
        </div>
        <div class="add-content_col">
          <span><i>*</i>确认密码</span>
          <span>
            <el-input
                v-model="password2" type="password" :disabled="UserMsg.type == 'edit'" @blur="confirmPassword"></el-input>
          </span>
        </div>
        <div class="add-content_col">
          <span><i>*</i>选择角色</span>
          <span>
            <el-select v-model="userForm['roleIdList']">
              <el-option
                  v-for="option in roleList"
                  :key="option.id"
                  :value="option.id"
                  :label="option.roleName"></el-option>
            </el-select>
          </span>
        </div>
        <div class="add-content_col">
          <span>手机号</span>
          <span>
            <el-input
                v-model="userForm['mobile']"></el-input>
          </span>
        </div>
        <div class="add-content_col">
          <span>部门</span>
          <span>
            <el-input
                v-model="userForm['deptName']"></el-input>
          </span>
        </div>
        <div class="add-content_col">
          <span>备注</span>
          <span>
            <el-input
                v-model="userForm['remarks']"></el-input>
          </span>
        </div>
      </div>
      <!--===-->
    </div>
    <!--按钮-->
    <div class="add-btn-box">
      <div class="add-btn" @click="$emit('CloseDialog')">取 消</div>
      <div class="add-btn" @click="addUser()">保 存</div>
    </div>
    <!--到底啦！===========================-->
  </div>
</template>

<script>
 import * as userAddApi from "@/api/System/user.js"
import {queryRoleApi} from  "@/api/System/role"
 import * as camersApi from "@/api/System/Camera.js"
export default {
  name: "addUser",
  props: ['UserMsg', 'checkDeptData'],
  data() {
    return {
      password:'',
      password2:'',
      userForm: {
        cameraIdList: [],

      },
      checkMenuDataId: [],
      //角色
      roleList:[],
      //摄像头
      CameraList:[]
    }
  },
  created() {
    this.getRole()
    this.getCamera()
    if (this.UserMsg.type == 'edit') {

      this.userForm = JSON.parse(JSON.stringify(this.UserMsg.row))
      //this.userForm['isAdmin'] = this.UserMsg.row.isAdmin + ''
      this.userForm.roleIdList = parseInt(this.userForm.roleList[0].id)

    } else {
      this.userForm.deptId = this.checkDeptData.id;
      this.userForm.deptName = this.checkDeptData.name;
    }
    console.log(this.checkDeptData);
    console.log(this.userForm);
  },
  methods: {
    //获取角色
    getRole(){
      queryRoleApi({}).then(res => {

        if(res.data.code != '2000') return this.$message.error({message:res.data.message,showClose:true,duration:1000});
        this.roleList = res.data.result.records
      })
    },
    //获取摄像头
    getCamera(){
      camersApi.queryCameraApi({}).then(res => {

        if(res.data.code != '2000') return this.$message.error({message:res.data.message,showClose:true,duration:1000});
        this.CameraList = res.data.result.records
        res.data.result.records.forEach(item => {
          this.userForm['cameraIdList'].push(item.id)
        })
      })
    },
    //新增用户
    addUser(){
      //校验
      if(!this.userForm.username) return this.$message.error({message:"用户名称不能为空！",showClose:true,duration:1000});
      //if(!this.userForm.isAdmin) return this.$message.error({message:"是否为管理员不能为空！",showClose:true,duration:1000});
      if(!this.userForm.roleIdList) return this.$message.error({message:"选择角色不能为空！",showClose:true,duration:1000});
      if(this.userForm.mobile){
        if(this.userForm.mobile.length != 11) return this.$message.error("请输入11位手机号码！")
        if (!/^1[3456789]\d{9}$/.test(this.userForm.mobile)) return this.$message.error("请输入正确的手机号！")
      }
      //
      if(this.UserMsg.type == 'edit') {//编辑用户
        this.userForm.roleIdList = [this.userForm.roleIdList]
        delete this.userForm.status
        delete this.userForm.isAdminName
        userAddApi.updateUserApi(this.userForm).then(res => {

          if(res.data.code != 2000) return this.$message.error({message:res.data.message,showClose:true,duration:1000});
          this.$message.success({message:"编辑用户成功",showClose:true,duration:1000});
          // this.$router.push('/system/userAdmin')
          this.$emit('CloseDialog',0)
        })
      }else{//新建用户
        if(this.password != this.password2)return this.$message.error({message:"两次密码输入不一致！",showClose:true,duration:1000});
        if(!this.userForm.password) return this.$message.error({message:"登录密码不能为空！",showClose:true,duration:1000});

        this.userForm.roleIdList = [this.userForm.roleIdList]
        userAddApi.registerUserApi(this.userForm).then(res => {

          if(res.data.code != 2000) return this.$message.error({message:res.data.message,showClose:true,duration:1000}),this.userForm.roleIdList = this.userForm.roleIdList[0];
          this.$message.success({message:"添加用户成功",showClose:true,duration:1000});
          // this.$router.push('/system/userAdmin')
          this.$emit('CloseDialog',0)
        })
      }

    },
    //确认密码
    confirmPassword(){
      if(this.UserMsg.type == 'add') {

        if(this.password != this.password2){
          this.$message.error({message:"两次密码输入不一致！",showClose:true,duration:1000});
        } else {
          this.userForm.password = this.password
        }
      }
    },

  }
}
</script>
