//添加摄像头
export function insertCameraGroupApi(query) {
  return request({
    url: '/apiIP/t-camera-group/add',
    method: 'post',
    data: query,
  })
}
//修改摄像头
export function updateCameraGroupApi(query) {
    return request({
        url: '/apiIP/t-camera-group/update',
        method: 'post',
        data: query,
    })
}
