import request from '@/utils/request'


//菜单查询
export function getUserApi(query) {
    return request({
      url: '/apiIP/system/menu/menuTree',
      method: 'get',
      data: query,
    })
  }

//查询角色
export function queryRoleApi(query) {
    return request({
        url: '/apiIP/sys-role/query',
        method: 'post',
        data: query,
    })
}
//删除角色
export function deleteRoleApi(query) {
    return request({
        url: '/apiIP/sys-role/delByIds',
        method: 'post',
        data: query,
    })
}
//批量删除角色
export function deleteAllRoleApi(query) {
    return request({
        url: '/apiIP/system/role/delete/batch',
        method: 'post',
        params: query,
    })
}
//新增角色
export function addRoleApi(query) {
    return request({
        url: '/apiIP/sys-role/add',
        method: 'post',
        data: query,
    })
}
//编辑角色
export function updateRoleApi(query) {
    return request({
        url: '/apiIP/sys-role/update',
        method: 'post',
        data: query,
    })
}
//菜单查询根据参数 查询json
export function queryMenuApi(query) {
    return request({
        url: '/apiIP/sys-menu/queryRecursionByParams',
        method: 'post',
        data: query,
    })
}
//根据roleId查询菜单ids
export function queryMenuIdsApi(query) {
    return request({
        url: '/apiIP/sys-role/queryMenuIdsByRoleId',
        method: 'post',
        data: query,
    })
}