//添加摄像头
export function insertCameraApi(query) {
  return request({
    url: '/apiIP/t-camera-info/insert',
    method: 'post',
    data: query,
  })
}
//修改摄像头
export function updateCameraApi(query) {
    return request({
        url: '/apiIP/t-camera-info/update',
        method: 'post',
        data: query,
    })
}
//查询摄像头
export function queryCameraApi(query) {
    return request({
        url: '/apiIP/t-camera-info/query',
        method: 'post',
        data: query,
    })
}
//删除摄像头
export function deleteCameraApi(query) {
    return request({
        url: '/apiIP/t-camera-info/delete',
        method: 'post',
        data: query,
    })
}
//
// 根据用户userId 查询拥有的摄像头权限，以及全部摄像头
export function CameraByUserApi(query) {
    return request({
        url: '/apiIP/t-camera-info/queryCameraByUserId',
        method: 'post',
        data: query,
    })
}
//根据平台编码获取rtsp 摄像头编码
export function getChannelsByIdApi(query) {
    return request({
        url: '/apiIP//ez/getChannelsById',
        method: 'post',
        data: {...query,sslProtocol:'https'}
    })
}
