<template>
  <div class="selectCamera-box">
    <div class="selectCamera-con">
<!--      <div class="selectCamera-title">摄像头列表</div>-->
      <div class="selectCamera-search">
        <div  class="selectCamera-input">
          <span>摄像头位置</span>
          <el-input
              v-model="params['cameraAddr']"
              placeholder="请输入摄像头位置"
              clearable
          ></el-input>
        </div>
        <div  class="selectCamera-input">
          <span>摄像头分组</span>
          <el-select
              v-model="params['groupName']"
              placeholder="请输入摄像头位置"
              clearable
          >
            <template>
              <el-option
                  v-for="option in CameraGroupList"
                  :key="option.value"
                  :value="option.value"
                  :label="option.label"></el-option>
            </template>
          </el-select>
        </div>
        <div class="selectCamera-btnBox search" >
          <span class="select-add-btn" @click.stop="getCameraByUser">查 询</span>
          <div class="select-add-btn" @click="restSearchForm">重 置</div>
        </div>
      </div>
      <div class="selectCamera-table">
        <!-- table-->
        <LTTableForm
            v-if="tableConfig.tableRefresh"
            ref='mulitpleTable'
            :tableConfig="tableConfig"
            @setSelectionTable="getSelectionTable"
            @getSelect="getSelect"
            @getSelectAll="getSelectAll"></LTTableForm>
      </div>
    </div>
    <div class="selectCamera-btn"></div>
    <div class="selectCamera-con on">
      <div class="selectCamera-title">
        已授权摄像头列表
        <span @click="emptyCamera">清空</span>
      </div>
      <ul class="selectCamera-list">
        <li v-for="(item,index) in selectCameraCheck" :key="index">
          <span>
            {{ item.cameraAddr }} - {{item.cameraCode}}
          </span>
          <i class="icon zhb-iconfont zhb-iconshanchu2" @click="deleteCamera(item)"></i>
        </li>
      </ul>
    </div>
    <!--按钮-->
    <div class="selectCamera-btnBox newSealAdd-btn" >
      <div class="select-add-btn" @click="$emit('CloseDialog')">取 消</div>
      <div class="select-add-btn" @click="saveCameraByUser">保 存</div>
    </div>
  </div>
</template>

<script>
import {queryCameraGroupApi} from "@/api/System/CameraGroup";
import * as camersApi from "@/api/System/Camera";
import * as userAddApi from "@/api/System/user";

export default {
  props:['UserInfo','UserIds'],
  data() {
    return {
      //搜索配置
      formConfig: {
        labelWidth: '100px',
        formItemList: [
          // {
          //   id: 1,
          //   type: 'select',
          //   prop: 'cameraCode',
          //   label: '摄像头编码',
          //   value: '',
          //   list:[]
          // },
          {
            id: 2,
            type: 'text',
            prop: 'cameraAddr',
            label: '摄像头位置',
            value: ''
          },
          {
            id: 3,
            type: 'select',
            prop: 'groupName',
            label: '摄像头分组名称',
            value: '',
            list:[]
          }
        ],
        isShowButtonRow: true,
        ShowButtonRowNums: 12
      },
      CameraGroupList:[],
      //表格配置
      tableConfig: {
        tableRefresh: true,
        tableHead: [
          {
            label: '矿名称',
            prop: 'mineName',
          },
          {
            label: '摄像头编码',
            prop: 'cameraCode',
          },
          {
            label: '摄像头位置',
            prop: 'cameraAddr',
          },
          {
            label: '预览图片',
            prop: 'picUrl',
            isLookPic:true,
            picList:[]
          },
        ],
        tableData: [],
        columnButton: [],
        //columnWidth: '130',
        // tableColWidth:'155',
        total: 0,
        pageSize: 10,
        currentPage: 1,
        isHiddenPage: true
      },
      //表格勾选
      checkTabelData: [],
      params:{},
      getCheck:[],
      selectCameraCheck:[],
      isLoadNum:1
    };
  },
  created() {
    this.queryCameraGroup()
    if(this.UserIds.length == 0){
      this.getCameraByUser()
    }

  },
  methods:{
    emptyCamera(){
      this.selectCameraCheck = []
      this.getCheck = []
      this.$nextTick(()=>{
        this.getShow()
      })
    },
    //查询摄像头分组
    queryCameraGroup(){
      queryCameraGroupApi(this.params).then(res => {
        if(res.data.code != '2000') return this.$message.error({message:res.data.message,showClose:true,duration:1000});
        if(res.data.result.records && res.data.result.records.length!= 0){
          var cameraGroupData = []
          res.data.result.records.forEach(item => {
            cameraGroupData.push({label:item.groupName,value:item.groupName})
          })
          this.CameraGroupList= cameraGroupData
        } else {
          this.CameraGroupList = []
        }


      }).catch(()=>{
        this.tableConfig.tableLoading = false
      })
    },
    //查询
    restSearchForm(){
      this.params = {}
      this.getCameraByUser()
    },
    //表格勾选数据
    getSelectionTable(val) {
      this.checkTabelData = val
    },
    //单个勾选
    getSelect(selection,row){
      console.log(selection, row);
      let delIndex
      let isDel = this.getCheck.some((item,index) => {
        if(item.id == row.id){
          delIndex = index
          return true
        }
      })
      let isSDel = this.selectCameraCheck.some((item,index) => {
        if(item.id == row.id){
          delIndex = index
          return true
        }
      })
      if(isDel){
        this.getCheck.splice(delIndex,1)
      } else {
        this.getCheck.push(row)
        this.getCheck = [...new Set(this.getCheck.map(item => item.id))].map(id => this.getCheck.find(item => item.id === id));

      }
      if(isSDel){
        this.selectCameraCheck.splice(delIndex,1)
      } else {
        this.selectCameraCheck.push(row)
        this.selectCameraCheck = [...new Set(this.selectCameraCheck.map(item => item.id))].map(id => this.selectCameraCheck.find(item => item.id === id));

      }
    },
    //全部勾选
    getSelectAll(selection){
      console.log(selection);
      if(selection.length != 0){
        let getCheck = [...selection,...this.getCheck]
        this.getCheck = [...new Set(getCheck.map(item => item.id))].map(id => getCheck.find(item => item.id === id));

        let selectCameraCheck = [...selection,...this.selectCameraCheck]
        this.selectCameraCheck = [...new Set(selectCameraCheck.map(item => item.id))].map(id => selectCameraCheck.find(item => item.id === id));

      } else if(selection.length == 0){
        let CameraId = [];
        this.tableConfig.tableData.forEach(item => {
          CameraId.push(item.id)
        })
        this.getCheck =  this.getCheck.filter(item => !CameraId.includes(item.id))
        this.selectCameraCheck =  this.selectCameraCheck.filter(item => !CameraId.includes(item.id))
        console.log("this.selectCameraCheck");
        console.log(this.selectCameraCheck);
      }
    },
    //表格勾选回显
    getShow(){

      this.$refs['mulitpleTable'].toggleRowSelection(this.getCheck)
    },
    //据用户userId 查询拥有的摄像头权限，以及全部摄像头
    getCameraByUser(data){
      if(data == 1){
        this.params = {}
      }

      var params = {
        userId:this.UserInfo.id,
        ...this.params
      }
      camersApi.CameraByUserApi(params).then(res => {
        if(res.data.code != '2000') return this.$message.error({message:res.data.message,showClose:true,duration:1000});
        this.tableConfig.tableData = res.data.result.allList.records
        this.tableConfig.total = res.data.result.allList.total
        //res.data.result.allList
        //this.getCheck = []
        console.log("this.isLoadNum=============");
        console.log(this.isLoadNum);
        if(this.isLoadNum == 1) {
          if(res.data.result.checkedList.length != 0){
          res.data.result.allList.records.forEach(item => {
            res.data.result.checkedList.forEach(subItem => {
              if(item.id == subItem.cameraId){
                this.getCheck.push(item)
                console.log(this.selectCameraCheck.indexOf(item));
                let isCheck = this.selectCameraCheck.some((sitem) => {
                  if(sitem.id == item.id){
                    return true
                  }
                })
                if(!isCheck){
                  this.selectCameraCheck.push(item)
                }

              }
            })
          })
        }

          this.isLoadNum++;
        } else {
          this.getCheck = this.selectCameraCheck
        }
        this.$nextTick(()=>{
          this.getShow()
        })
      })
    },
    //取消授权
    deleteCamera(item){
      this.getCheck.forEach((i,index) => {
        if(item.id == i.id){
          this.getCheck.splice(index,1)
        }
      })
      this.selectCameraCheck.forEach((i,index) => {
        if(item.id == i.id){
          this.selectCameraCheck.splice(index,1)
        }
      })
      this.$nextTick(()=>{
        this.getShow()
      })
    },
    //保存
    saveCameraByUser(){

      var params = {
        ids:[],
        id:'',
        cameraIdList:[]
      }
      this.getCheck.forEach(item => {
        params.cameraIdList.push(item.id)
      })
      if(this.UserIds.length == 0){
        params.id = this.UserInfo.id
        delete params.ids
        userAddApi.updateUserApi(params).then(res => {
          if(res.data.code != 2000) return this.$message.error({message:res.data.message,showClose:true,duration:1000});
          this.$message.success({message:"更新用户授权摄像头成功",showClose:true,duration:1000});
          // this.$router.push('/system/userAdmin')
          this.$emit('CloseDialog',0)
        })
      } else {
        params.ids = this.UserIds
        delete params.id
        userAddApi.setCameraPermissionsApi(params).then(res => {
          if(res.data.code != 2000) return this.$message.error({message:res.data.message,showClose:true,duration:1000});
          this.$message.success({message:"更新用户授权摄像头成功",showClose:true,duration:1000});
          // this.$router.push('/system/userAdmin')
          this.$emit('CloseDialog',0)
        })
      }


    }
  }
};
</script>
<style lang="scss">
.selectCamera-box{
  width: 100%;
  height: 100%;
  display: flex;
  flex-wrap: wrap;
  margin-top: 20px;
  justify-content: center;
  .selectCamera-con{
    width: calc(70% - 10px);
    height: calc(100% - 60px);
    border: 1px solid  rgba(18, 33, 183, 1)!important;
    box-sizing: border-box;
    border-radius: 15px;
    padding: 0 12px;
    &.on{
      width: calc(30% - 50px);
      padding: 0;
    }
    .selectCamera-title{
      width: 100%;
      height: 40px;
      line-height: 40px;
      background-color: rgba(18, 33, 183, 1)!important;
      text-indent: 20px;
      color:#fff;
      border-radius: 15px 15px 0 0;
      font-size: 15px;
      position: relative;
      span{
        cursor: pointer;
        color:#fff;
        position: absolute;
        top:50%;
        right:20px;
        transform: translateY(-50%);
      }
    }
    .selectCamera-search{
      width: 100%;
      height:100px;
      display: flex;
      position: relative;
      .selectCamera-input{
        width: calc(100% / 3);
        color:#ffffff;
        display: flex;
        align-items: center;
        >span{
          width: 80px;
          white-space: nowrap;
          margin: 0 5px;

        }

        .el-input__inner {
          height: 40px;
          background: transparent !important;
          border: 1px solid #9BB1C2;
          color: #fff !important;
        }
      }
    }
    .selectCamera-table{
      width: 100%;
      height:calc(100% - 120px);
      margin-top: 15px;
    }
    .selectCamera-list{
      width: 100%;
      height: calc(100% - 40px);
      overflow: auto;
      &::-webkit-scrollbar{width: 0}
      li{
        width: 100%;
        height: 50px;
        line-height: 50px;
        text-indent: 20px;
        color:#ffffff;
        font-size: 16px;
        background: #002550;
        span{
          width: calc(100% - 52px);
          display: inline-block;
          white-space: nowrap;
          float: left;
          overflow: hidden;
        }
        &:nth-of-type(2n+1){
          background: #001B40;
        }
        i{
          float: right;
          cursor: pointer;
          margin-right: 20px;
          width: 30px;
        }
      }
    }
  }
  .selectCamera-btn{
    width: 20px;
  }
  .selectCamera-btnBox{
    width: 100%;
    height: 40px;
    display: flex;
    align-items: center;
    justify-content: center;
    margin-top: 2vh;
    z-index: 1000;
    .select-add-btn{
      width: 12vh;
      height: 6vh;
      line-height: 6vh;
      text-align: center;
      color:#ffffff;
      margin: 0 .5vw;
      cursor: pointer;
      background: url("~@/assets/image/icon-cx.png") no-repeat;
      background-size: 100% 100%;
    }
    &.search{
      width: auto;
      position: absolute;
      top:50%;
      right:0;
      transform: translateY(-50%);
      margin: 0;
      .select-add-btn{
        margin: 0;
        background: url("~@/assets/image/icon-cx.png") no-repeat;
        background-size: 100% 100%;
      }
    }
  }

  ::v-deep .el-table tr:nth-of-type(2n+1){
    background:  #001B40!important;
  }
  ::v-deep .el-table tr:nth-of-type(2n){
    background:  #002550!important;
  }
  ::v-deep .el-table th>.cell{
    color: #ffffff!important;
    text-align: center!important;
  }
  ::v-deep .el-table .cell{
    color: #ffffff!important;
    text-align: center!important;
  }
  ::v-deep .el-table th.is-leaf,.el-table td{
    border-bottom:none!important;
    border:none;
  }
  ::v-deep .el-table tbody tr:hover > td,.el-table tbody tr:hover > td{
    background-color: #002550 !important;
  }
  ::v-deep .el-table__body tr.hover-row.current-row > td,
  ::v-deep .el-table__body tr.hover-row.el-table__row--striped.current-row > td,
  ::v-deep .el-table__body tr.hover-row.el-table__row--striped > td,
  ::v-deep .el-table__body tr.hover-row > td {
    background-color: #002550 !important;
  }
  ::v-deep .el-table{
    background: none;
  }
  ::v-deep .el-table--enable-row-hover .el-table__body tr:hover>td {/*表格选中颜色*/
    background-color:#002550!important;
  }
  ::v-deep .el-table::before{/*表底部边框*/
    height: 0px!important;
  }
  ::v-deep .el-table__fixed-right::before, .el-table__fixed::before{
    height: 0;
  }
  ::v-deep .el-checkbox__inner{
    background-color: transparent!important;
    border: 1px solid #6BB7FF!important;
  }
}

</style>