<template>
  <div class="min-body" style="position: relative;width:70%;margin:9vh auto 0 auto;height: calc(100% - 6vh); ">
    <!--main-->
    <div class="body-main" style="height: calc(100% - 6vh)">
      <!--con-->
      <div class="addDetailPage-row" style="height: 4vh">
        <div class="detailPage-col" style="width: 50%;">
          <span><i>*</i>部门名称</span>
          <span>
            <el-input
                v-model="deptForm['name']"></el-input>
          </span>
        </div>
        <div class="detailPage-col" style="width: 50%;">
          <span><i>*</i>排序</span>
          <span>
            <el-input
                v-model="deptForm['sort']"></el-input>
          </span>
        </div>
        <div class="detailPage-col" style="width: 50%;">
          <span>部门编码</span>
          <span>
            <el-input
                v-model="deptForm['code']"></el-input>
          </span>
        </div>
        <div class="detailPage-col" style="width: 50%;">
          <span>备注</span>
          <span>
            <el-input
                v-model="deptForm['remarks']"></el-input>
          </span>
        </div>
      </div>
      <!--===-->
    </div>
    <!--按钮-->
    <div class="add-btn-box newSealAdd-btn">
      <div class="seal-add-btn" @click="$emit('CloseDialog')">取 消</div>
      <div class="seal-add-btn" @click="addDept()">保 存</div>
    </div>
    <!--到底啦！===========================-->
  </div>
</template>

<script>
import * as deptApi from '@/api/System/user.js';

export default {
  name: 'AddDept',
  props: {
    addDialog: {
      type: Object,
      required: true,
      default: () => ({
        dialogVisible: false,
        title: '新增部门',
        type: 'add',
        data: null,
        parentDept: null
      })
    }
  },
  data() {
    return {
      menuData: [],
      defaultProps: {
        children: 'childMenuArray',
        label: 'name'
      },
      isShowTree: true,
      deptForm: {
        name: '',
        sort: '',
        code: '',
        remarks: ''
      }
    };
  },
  mounted() {
    if (this.addDialog.type === 'edit') {
      this.deptForm.name = this.addDialog.data.name || '';
      this.deptForm.sort = this.addDialog.data.sort || '';
      this.deptForm.code = this.addDialog.data.code || '';
      this.deptForm.remarks = this.addDialog.data.remarks || '';
    }
  },
  methods: {
    addDept() {
      if (!this.deptForm.name) {
        return this.$message.error({
          message: '部门名称不能为空！',
          showClose: true,
          duration: 1000
        });
      }

      if (!this.deptForm.sort) {
        return this.$message.error({
          message: '排序不能为空！',
          showClose: true,
          duration: 1000
        });
      }

      const params = {
        name: this.deptForm.name,
        sort: this.deptForm.sort,
        code: this.deptForm.code || '',
        remarks: this.deptForm.remarks || ''
      };

      if (this.addDialog.type === 'edit') {
        // 更新部门
        params.id = this.addDialog.data.id;
        params.parentId = this.addDialog.parentDept?.id || '';
        deptApi.updateDeptApi(params).then(res => {
          if(res.data.code != '2000') return this.$message.error({message:res.data.message,showClose:true,duration:1000});

          this.$message.success({message: '更新部门成功', showClose: true, duration: 1000});
          this.$emit('getCloseDialog', 0);
          this.addDialog.dialogVisible = false;
        });
      } else {
        // 新增部门
        params.parentId = this.addDialog.data?.id || '';
        deptApi.addDeptApi(params).then(res => {
          if (res.data.code != '2000') {
            return this.$message.error({
              message: res.data.message,
              showClose: true,
              duration: 1000
            });
          }
          this.$message.success({message: '新建部门成功', showClose: true, duration: 1000});
          this.addDialog.dialogVisible = false;
          this.$emit('getCloseDialog', 0);
        });
      }
    }
  }
};
</script>


