<!-- dept-tree.vue -->
<template>
  <div class="dept-box">
    <div class="dept-title" v-if="type != 'select'">组织树</div>
    <div style="margin: 10px 0;padding: 0 10px;" v-if="type != 'select'">
      <el-input
          v-model="deptTreeFilterValue"
          placeholder="请输入部门名称"
          style="width: 100%;"
          clearable
          @input="filterDeptTree"
      ></el-input>
    </div>
    <div class="dept-tree">
      <el-tree
          ref="treeRef"
          :data="TreeData"
          :props="props"
          node-key="id"
          highlight-current
          show-checkbox
          :check-strictly="true"
          :check-on-click-node="true"
          :expand-on-click-node="false"
          :default-expand-all="!deptTreeFilterValue"
          :filter-node-method="filterNode"
          @check-change="handleNodeCheck"
          @node-contextmenu="handleNodeContextMenu"
      >
      </el-tree>
    </div>

    <!--按钮-->
    <div v-if="type=='select'" class="add-btn-box newSealAdd-btn" style="bottom: 1.5vh !important;">
      <div class="seal-add-btn" @click="$emit('closeZhbDialog')">取 消</div>
      <div class="seal-add-btn" @click="setCheckDept">保 存</div>
    </div>
    <div v-if="isShowContectMenu" class="dept-btn" :style="ContectMenuStyle">
      <el-button type="primary" class="Menu-btn" @click="addDeptFun">新增</el-button>
      <el-button class="Menu-btn" @click="editDeptFun">编辑</el-button>
      <el-button class="Menu-btn" @click="deleteDeptFun">删除</el-button>
    </div>
    <!--新增组织-->
    <ZhbDialog class="RoleZhbDialog" v-if="addDialog.dialogVisible" :ZhbDialogMsg="ZhbDialogMsg2" @CloseDialog="addDialog.dialogVisible = false">
      <template  slot>
        <addDept v-if="addDialog.dialogVisible" :addDialog="addDialog" @getCloseDialog="getCloseDialog"></addDept>
      </template>
    </ZhbDialog>
  </div>
</template>

<script>
import { getDeptApi, delDeptApi } from "@/api/System/user";
import addDept from "./addDept.vue";

export default {
  components: {
    addDept,
  },
  props: ['type'],
  data() {
    return {
      deptTreeFilterValue: '', // 部门树过滤值
      ZhbDialogMsg2: {
        title: "新增部门"
      },
      addDialog: {
        dialogVisible: false,
        title: '新增部门',
        type: 'add',
        data: null,
        parentDept: null,
      },
      isShowContectMenu: false,
      ContectMenuStyle: {
        top: "50%",
        left: "auto",
      },
      currentDept: null,
      parentDept: null,
      checkDept: null,
      TreeData: [],
      props: {
        label: "name",
        children: "children",
      },
    };
  },
  methods: {
    handleNodeCheck(data, isCheck) {
      if (isCheck) {
        this.$refs.treeRef.setCheckedKeys([]);
        this.$refs.treeRef.setChecked(data, true);
        this.checkDept = data;
        this.$emit('setCheckDept', this.checkDept);
      } else {
        if (this.checkDept && this.checkDept.id === data.id) {
          this.checkDept = null;
          this.$emit('setCheckDept', null);
        }
      }
    },
    resetChecked() {
      this.$refs.treeRef.setCheckedKeys([], false);
    },
    handleNodeContextMenu(event, data, node) {
      if (this.type == "select") {
        return;
      }
      this.isShowContectMenu = false;
      event.preventDefault();
      this.parentDept = node.parent.data;
      this.currentDept = data;
      this.ContectMenuStyle.top = event.clientY + "px";
      this.ContectMenuStyle.left = event.clientX + 50 + "px";
      this.$nextTick(() => {
        this.isShowContectMenu = true;
      });
    },
    getDept() {
      getDeptApi().then((res) => {
        if(res.data.code != '2000') return this.$message.error({message:res.data.message,showClose:true,duration:1000});
        this.TreeData = res.data.result;
      });
    },
    // 过滤节点方法
    filterNode(value, data) {
      if (!value) return true;
      return data.name.toLowerCase().indexOf(value.toLowerCase()) !== -1;
    },

    // 过滤部门树
    filterDeptTree() {
      this.$nextTick(() => {
        this.$refs.treeRef.filter(this.deptTreeFilterValue);
      });
    },

    addDeptFun() {
      this.addDialog.data = this.currentDept;
      this.addDialog.title = "新增部门";
      this.addDialog.type = "add";
      this.addDialog.dialogVisible = true;
    },
    editDeptFun() {
      this.addDialog.data = this.currentDept;
      this.addDialog.parentDept = this.parentDept;
      this.addDialog.title = "编辑部门";
      this.addDialog.type = "edit";
      this.addDialog.dialogVisible = true;
    },
    deleteDeptFun() {
      this.$confirm('此操作将永久删除该部门, 是否继续?', '提示', {
        confirmButtonText: '确定',
        cancelButtonText: '取消',
        type: 'warning'
      }).then(() => {
        delDeptApi({ id: this.currentDept.id }).then(res => {
          if (res.data.code != '2000') {
            return this.$message.error({ message: res.data.message, showClose: true, duration: 1000 });
          }
          this.getDept();
          this.$message.success({ type: 'success', message: '删除成功！' });
        });
      }).catch(() => {
        this.$message.info({ type: 'info', message: '已取消删除' });
      });
    },
    getCloseDialog() {
      this.addDialog.dialogVisible = false;
      this.getDept();
    },
    setCheckDept() {
      if (!this.checkDept) {
        return this.$message.warning({ message: "请选择部门", showClose: true, duration: 1000 });
      }
      this.$emit('GetCheckDept', this.checkDept);
    }
  },
  mounted() {
    document.addEventListener("click", () => {
      this.isShowContectMenu = false;
    });
    this.getDept();
  },
  watch: {
    deptTreeFilterValue(val) {
      this.filterDeptTree();
    }
  }
};
</script>


<style lang="scss" scoped>
.dept-box {
  height: calc(100% - 20px);
  margin-top: 18px;
  color:#000;
  box-sizing: border-box;
  position: relative;
  box-shadow: 0 2px 12px 0 rgba(51,248,214, 0.5);
  .dept-tree{
    height: calc(100% - 100px);
    overflow: auto;
    &::-webkit-scrollbar{
      width: 6px;
    }
    &::-webkit-scrollbar-thumb{
      background: #072243;
      border-radius: 4px;
    }
    &::-webkit-scrollbar-track{
      background: #CED2D8;
      border-radius: 4px;
    }
  }
  .dept-btn {
    position: fixed;
    background: #fff;
    border: 1px solid #ebeef5;
    box-shadow: 0 2px 12px 0 rgba(0, 0, 0, 0.1);
    z-index: 1000;
    border-radius: 6px;
    padding:12px 12px 0 12px;
    .Menu-btn {
      display: block;
      margin: 0 !important;
      margin-bottom: 10px !important;
      width: 60px;
      height: 32px;
      padding: 0!important;
      &:nth-of-type(1) {
        color: #fff !important;
        border: 1px solid #4076f6;
        i {
          color: #000 !important;
        }

        &:hover {
          opacity: 0.8;
        }
      }

      &:nth-of-type(2) {
        color: #4076f6;
        border: 1px solid #4076f6;

        &:hover {
          opacity: 0.8;
        }
      }

      &:nth-of-type(3) {
        border: 1px solid #ea0000;
        color: #ea0000;

        &:hover {
          background: rgba(240, 177, 171, 0.4);
          opacity: 0.8;
        }
      }
    }
  }

  .dept-title {
    height: 40px;
    line-height: 40px;
    padding-left: 10px;
    font-size: 14px;
    color: #fff;
    border-bottom: 1px solid #01F1FF;
    position: relative;
    text-indent: 10px;
  }

  .el-tree {
    .el-tree-node:focus {
      .el-tree-node__content {
        background-color: #17e6e9 !important;
      }
    }
  }
}
</style>
<style>
.el-tree--highlight-current .el-tree-node.is-current>.el-tree-node__content{
  color: #000!important;
}
</style>
