* @Descripttion: 用户管理
-->
<template>
  <LTPages
      is-normal
      :title="'用户管理'"
  >
    <template v-slot:content>
      <LTSearchForm
          type="LargeScreen"
          :formConfig="formConfig"
          @setSearchFields="getSearchFields">
      </LTSearchForm>
      <div class="Page-Table-box User-Main-box">

        <div class="dept-tree-box">
          <deptTree @setCheckDept="GetCheckDept"></deptTree>
        </div>
        <div class="User-Table-box">
          <LTActionsForm :buttonConfig="buttonConfig" style="margin: 10px 0;"></LTActionsForm>
          <LTTableForm
              v-if="tableConfig.tableRefresh"
              v-loading="tableConfig.tableLoading"
              :tableConfig="tableConfig"
              @tablePageForm="getTableForm"
              @setSelectionTable="getSelectionTable"
              style="height: calc(100% - 75px);"
          ></LTTableForm>
        </div>
      </div>
      <!--添加用户-->
      <LTDialog
          v-if="UserMsg.isShow"
          :DialogLTMsg="UserMsg"
          @close="UserMsg.isShow = false">
        <addUser :UserMsg="UserMsg" :checkDeptData="checkDeptData" @CloseDialog="CloseDialog"></addUser>
      </LTDialog>
      <!--摄像头授权-->
      <LTDialog
          v-if="isShowTable"
          :DialogLTMsg="SelectCameraMsg"
          @close="isShowTable = false">
        <SelectCamera :UserInfo=UserInfo :UserIds="UserIds" @CloseDialog="isShowTable = false"></SelectCamera>
      </LTDialog>


    </template>
  </LTPages>
</template>
<script>
import * as userApi from "@/api/System/user.js";
import deptTree from "./components/dept-tree.vue";
import addUser from "./components/addUser.vue";
import SelectCamera from "./components/SelectCamera";

export default {
  name: 'User',
  components: {
    deptTree,
    addUser,
    SelectCamera
  },
  data() {
    return {
      //搜索配置
      formConfig: {
        labelWidth: "100px",
        itemNum: 5,
        formItemList: [
          {
            id: 1,
            type: 'text',
            prop: 'userName',
            label: '用户名称',
            value: ''
          }
        ]
      },
      // 表格上方按钮
      buttonConfig: [

        {
          label: '添加',
          icon: "icon zhb-iconfont zhb-iconxinjian1",
          click: () => {
            //
            if (!this.checkDeptData) return this.$message.warning({
              message: "请选择一个部门！",
              showClose: true,
              duration: 1000
            });
            this.UserMsg.type = 'add';
            this.UserMsg.title = '新增用户';
            this.UserMsg.isShow = true;
          }
        },
        {
          label: '删除',
          icon: "icon zhb-iconfont zhb-iconshanchu2",
          click: () => {
            if (this.checkTabelData.length == 0) return this.$message.warning({
              message: "请至少选择一条表格数据！",
              showClose: true,
              duration: 1000
            });
            this.$confirm('此操作将永久删除该用户, 是否继续?', '提示', {
              confirmButtonText: '确定',
              cancelButtonText: '取消',
              type: 'warning'
            }).then(() => {

              var ids = []
              this.checkTabelData.forEach(item => {
                ids.push(item.id)
              })
              userApi.deleteUserApi({ids: ids}).then(res => {
                if (res.data.code != '2000') return this.$message.error({
                  message: res.data.message,
                  showClose: true,
                  duration: 1000
                });
                this.queryUser()
                this.$message({
                  type: 'success',
                  message: '删除成功！'
                });
              })


            }).catch(() => {
              this.$message({
                type: 'info',
                message: '已取消删除'
              });
            });
          }
        },
        {
          label: '重置密码',
          icon: "icon zhb-iconfont zhb-iconzhongzhimima",
          isHiddenShow: this.isHiddenShow,
          click: () => {
            if (this.checkTabelData.length == 0 || this.checkTabelData.length > 1) return this.$message.warning({
              message: "请选择一条表格数据！",
              showClose: true,
              duration: 1000
            });
            this.$confirm('此操作将重置密码, 是否继续?', '提示', {
              confirmButtonText: '确定',
              cancelButtonText: '取消',
              type: 'warning'
            }).then(() => {
              userApi.resetPasswordApi({id: this.checkTabelData[0].id}).then(res => {
                if (res.data.code != '2000') return this.$message.error({
                  message: res.data.message,
                  showClose: true,
                  duration: 1000
                });
                this.queryUser()
                this.$message.success({message: res.data.message, showClose: true, duration: 1000});

              })
            }).catch(() => {
              this.$message({
                type: 'info',
                message: '已取消密码重置'
              });
            });
          }
        },
      ],
      //表格配置
      tableConfig: {
        tableRefresh: true,
        tableHead: [
          {
            label: '用户名称',
            prop: 'username',
          },
          // {
          //   label: '是否管理员',
          //   prop: 'isAdminName',
          // },
          {
            label: '角色名称',
            prop: 'roleName',
          },
          {
            label: '手机号',
            prop: 'mobile',
          },
          {
            label: '部门',
            prop: 'dept',
          },
          {
            label: '创建时间',
            prop: 'createTime',
          },
        ],
        tableData: [],
        columnButton: [
          {
            label: '摄像头授权',
            click: (row) => {
              this.UserIds = []
              this.isShowTable = true
              this.UserInfo = row
            }
          },
          {
            label: '编辑',
            icon: "zhb-iconwenbenbianjitianchong",
            click: (row) => {
              this.UserMsg.row = row;
              this.UserMsg.type = 'edit';
              this.UserMsg.title = '编辑用户';
              this.UserMsg.isShow = true;
            }
          },
          {
            label: '删除',
            icon: "zhb-iconwenbenbianjitianchong",
            click: (row) => {
              console.log(row);
              this.$confirm('此操作将永久删除该用户, 是否继续?', '提示', {
                confirmButtonText: '确定',
                cancelButtonText: '取消',
                type: 'warning'
              }).then(() => {

                var ids = [row.id]
                userApi.deleteUserApi({ids: ids}).then(res => {
                  if (res.data.code != '2000') return this.$message.error({
                    message: res.data.message,
                    showClose: true,
                    duration: 1000
                  });
                  this.queryUser()
                  this.$message({
                    type: 'success',
                    message: '删除成功！'
                  });
                })


              }).catch(() => {
                this.$message({
                  type: 'info',
                  message: '已取消删除'
                });
              });
            }
          },
        ],
        columnWidth: '250',
        // tableColWidth:'155',
        total: 0,
        pageSize: 20,
        currentPage: 1,
      },
      //表格勾选
      checkTabelData: [],
      //查询参数
      params: {
        pageSize: 20,
        currentPage: 1,
      },
      UserMsg: {
        isShow: false,
        title: '添加用户',
        showCloseBtn: true,
        styles: {
          width: '50%',
          height: '80%'
        }
      },
      //摄像头授权
      UserInfo: {},
      UserIds: [],
      isShowTable: false,
      SelectCameraMsg: {
        title: '摄像头授权',
        showCloseBtn: true,
        styles: {
          width: '80%',
          height: '80%'
        }
      },
      // 勾选部门
      checkDeptData: null,


    }
  },
  created() {
    this.queryUser()
  },
  methods: {
    // 查询
    GetCheckDept(val) {
      this.checkDeptData = val
      this.params.deptId = val?.id;
      this.queryUser();
    },
    getSearchFields(data) {
      console.log(data);
      if (data.type != 'reset') {
        this.params.username = data.username;
        this.params.ip = data.ip;
        if (data.alarmTime && data.alarmTime.length != 0) {
          this.params.createTime = data.alarmTime[0] + "," + data.alarmTime[1];
        } else {
          delete this.params.createTime;
        }
        this.params.currentPage = 1;
        this.tableConfig.currentPage = 1;
      } else { //重置
        this.params = {
          pageSize: 20,
          currentPage: 1
        }
      }
      this.queryLog();
    },
    queryUser() {
      userApi.queryUserApi(this.params).then(res => {
        this.tableConfig.tableRefresh = true
        if (res.data.code != '2000') return this.$message.error({
          message: res.data.message,
          showClose: true,
          duration: 1000
        });
        res.data.result.records.forEach(item => {
          item.status == 0 ? (item.status = '禁用') : (item.status == 1 ? item.status = '正常' : '')
          item.tableConfig == 0 ? (item.lockStatusName = '锁住') : (item.lockStatus == 1 ? item.lockStatusName = '正常' : '')
          item.isAdmin == 0 ? (item.isAdminName = '否') : (item.isAdmin == 1 ? item.isAdminName = '是' : '')
          item.roleName = item.roleList[0].roleName
        })
        this.tableConfig.total = res.data.result.total
        this.tableConfig.tableData = res.data.result.records
      }).catch(() => {

        this.tableConfig.tableRefresh = true
      })
    },
    //表格勾选数据
    getSelectionTable(val) {
      this.checkTabelData = val
    },
    //表格分页变化回调
    getTableForm(page) {
      this.tableConfig.pageSize = page.pageSize;
      this.tableConfig.currentPage = page.pageNum;
      this.params.pageSize = page.pageSize;
      this.params.currentPage = page.pageNum;
      this.queryLog();
    },

    //关闭新增角色
    CloseDialog(data) {
      this.UserMsg.isShow = false
      if (data == 0) {
        this.queryUser()
      }
    },

  }
}
</script>
<style scoped lang="scss">
.User-Main-box {
  margin-top: 15px;
  height: calc(100% - 90px);
  display: flex;
  justify-content: space-between;

  .User-Table-box {
    width: calc(100% - 300px);
  }

  .dept-tree-box {
    width: 280px;
    height: 100%;
    margin-right: 20px;

    ::v-deep .el-input__inner {
      background: transparent;
    }

    ::v-deep .el-tree {
      background: transparent;
      color: #ffffff;
    }

    ::v-deep .el-tree-node__content:hover,
    ::v-deep .el-upload-list__item:hover,
    ::v-deep .el-tree--highlight-current .el-tree-node.is-current > .el-tree-node__content,
    ::v-deep .el-tree--highlight-current .el-tree-node.is-checked > .el-tree-node__content {
      background: #324279;
      color: #ffffff !important;
    }
  }
}
</style>